const now = new Date();
const results = [];

for (const item of $input.all()) {
  const lead = item.json;
  if (!lead.timestamp || lead.status === 'Closed' || lead.status === 'Deal Closed') continue;

  const leadDate = new Date(lead.timestamp);
  const daysSince = Math.floor((now - leadDate) / (1000 * 60 * 60 * 24));

  let stage = null;
  if (daysSince === 1) stage = 'day1';
  else if (daysSince === 3) stage = 'day3';
  else if (daysSince === 7) stage = 'day7';
  else if (daysSince === 30) stage = 'day30';

  if (stage && lead.last_followup_stage !== stage) {
    results.push({ json: { ...lead, followup_stage: stage } });
  }
}

return results;
